[Form]
public class FWFTextBlockGroupAdd_Product extends FormRun
{
    FWFTextBlockGroup	currentFWFTextBlockGroup;
    Object              caller;

}

/// <summary>
///  Sets the state of the control on the depending on the formdatasource record selected.
/// </summary>
/// <param name="_formDataSource">
///  The form dtaSource.
/// </param>
/// <param name="_control">
///  The FormControl that needs to be enabled or disabled based on the FormdataSource selected record.
/// </param>
void setControlState(FormDataSource _formDataSource, FormControl _control)
{
    Common selectedRecord;

    selectedRecord = _formDataSource.getFirst(true)? _formDataSource.getFirst(true): _formDataSource.cursor();
    _control.enabled(selectedRecord.RecId);
}

    /// <summary>
    ///  Adds the selected <c>InventTable</c> record to the temporary table.
    /// </summary>
    void selectProduct()
    {
        InventTable				  selectedInventTable;
        FWFTextBlockGroupAssign   tmpFWFTextBlockGroupAssign;

        tmpFWFTextBlockGroupAssign.setTmp();

        // Are there any marked records?
        for (selectedInventTable = inventTable_ds.getFirst(1) ? inventTable_ds.getFirst(1) : inventTable_ds.cursor();
			 selectedInventTable;
			 selectedInventTable = inventTable_ds.getNext())
        {
            tmpFWFTextBlockGroupAssign.setTmpData(tmpFWFTextBlockGroupAssignSelected);
            select firstonly tmpFWFTextBlockGroupAssign
				where tmpFWFTextBlockGroupAssign.GroupId == currentFWFTextBlockGroup.Id
				   && tmpFWFTextBlockGroupAssign.Module  == currentFWFTextBlockGroup.Module
                   && tmpFWFTextBlockGroupAssign.RefId   == selectedInventTable.ItemId;

            if (! tmpFWFTextBlockGroupAssign.RecId)
            {
                tmpFWFTextBlockGroupAssign.clear();
                tmpFWFTextBlockGroupAssign.initValue();
                tmpFWFTextBlockGroupAssign.GroupId = currentFWFTextBlockGroup.Id;
                tmpFWFTextBlockGroupAssign.Module  = currentFWFTextBlockGroup.Module;
                tmpFWFTextBlockGroupAssign.RefId   = selectedInventTable.ItemId;

                tmpFWFTextBlockGroupAssign.doInsert();
            }
        }
    }

/// <summary>
///  Deletes the selected record from the temporary table.
/// </summary>
void deselectProduct()
{
    ttsbegin;

    if (tmpFWFTextBlockGroupAssignSelected_ds.anyMarked())
    {
        tmpFWFTextBlockGroupAssignSelected_ds.deleteMarked();
    }
    else if (tmpFWFTextBlockGroupAssignSelected_ds.getFirst())
    {
        tmpFWFTextBlockGroupAssignSelected_ds.delete();
    }

    ttscommit;
}

public void init()
{
    if (!element.args()			  ||
        !element.args().caller()  ||
        !element.args().record()  ||
        !element.args().dataset() ||
         element.args().dataset() != tablenum(FWFTextBlockGroup))
    {
        throw error(strfmt("@SYS22678",element.name()));
    }

    caller = element.args().caller();
    currentFWFTextBlockGroup.data(element.args().record());

    super();
}

/// <summary>
///  Adds all the records from the temporary table to the <c>FWFTextBlockGroupAssign</c> table.
/// </summary>
void updateGroupAssign()
{
    int                     nAdded = 0;

    FWFTextBlockGroupAssign	tmpFWFTextBlockGroupAssign;

    tmpFWFTextBlockGroupAssign.setTmp();
    tmpFWFTextBlockGroupAssign.setTmpData(tmpFWFTextBlockGroupAssignSelected);

    ttsbegin;
    while select * from tmpFWFTextBlockGroupAssign
    {
        if (FWFTextBlockGroupAssign::insertTextBlockGroupAssign(tmpFWFTextBlockGroupAssign.GroupId,
                                                                tmpFWFTextBlockGroupAssign.Module,
                                                                tmpFWFTextBlockGroupAssign.RefId))
        {
            nAdded++;
        }

    }
    ttscommit;

    // notify parent FORM to refresh
    if (nAdded && formHasMethod(caller, identifierStr(refreshReferenceGrid)))
    {
        caller.refreshReferenceGrid();
    }
}

public void executeQuery()
{
    QueryBuildDataSource	qbds = FWFTextBlockGroup_ds.queryBuildDataSource();

    qbds.addRange(fieldNum(FWFTextBlockGroup, Id)).value(currentFWFTextBlockGroup.Id);

    super();

    // based on if there are any records available for selection .
    element.setControlState(InventTable_ds, commandButtonAdd);
}

public boolean validateDelete()
{
    // call the table buffer validateDelete directly
    // to suppress the delete confirmation message box.
    return tmpFWFTextBlockGroupAssignSelected.validateDelete();
}

public void executeQuery()
{
    super();

    // enable/disable the Remove button, based on if there are any records.
    element.setControlState(tmpFWFTextBlockGroupAssignSelected_ds, commandButtonRemove);
}
